using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

/// <summary>
/// A static class providing methods to download content from multiple URIs concurrently.
/// </summary>
public static class Downloader
{
    /// <summary>
    /// Downloads content from all provided URIs concurrently.
    /// </summary>
    /// <param name="uris">An enumerable of URIs to fetch content from.</param>
    /// <param name="fetch">A delegate that performs the actual fetch operation for a single URI.</param>
    /// <param name="cancellationToken">A cancellation token to observe while waiting for the tasks to complete.</param>
    /// <returns>
    /// A task that represents the asynchronous operation. The task result contains an array of strings,
    /// with each string being the content fetched from the corresponding URI in the input sequence.
    /// </returns>
    /// <exception cref="ArgumentNullException">Thrown if <paramref name="uris"/> or <paramref name="fetch"/> is null.</exception>
    /// <exception cref="OperationCanceledException">Thrown if the operation is canceled via the <paramref name="cancellationToken"/>.</exception>
    public static async Task<string[]> DownloadAllAsync(
        IEnumerable<Uri> uris,
        Func<Uri, CancellationToken, Task<string>> fetch,
        CancellationToken cancellationToken)
    {
        ArgumentNullException.ThrowIfNull(uris);
        ArgumentNullException.ThrowIfNull(fetch);

        // Create and start all tasks concurrently.
        // By calling ToList(), we ensure that the Select statement is executed for all URIs,
        // which in turn calls the 'fetch' delegate and starts each download task. This is key
        // to achieving concurrency, as opposed to awaiting each task inside a loop.
        var downloadTasks = uris.Select(uri => fetch(uri, cancellationToken)).ToList();

        // Asynchronously wait for all the download tasks to complete.
        // Task.WhenAll aggregates multiple tasks into a single task that completes when all
        // of the supplied tasks have completed.
        // The results array will be in the same order as the 'uris' enumerable.
        // If any of the tasks are cancelled, Task.WhenAll's resulting task will be cancelled,
        // and awaiting it will throw an OperationCanceledException, fulfilling the requirement
        // to stop promptly.
        string[] results = await Task.WhenAll(downloadTasks);

        return results;
    }
}

