    /// </summary>
    /// <param name="uris">The collection of URIs to fetch.</param>
    /// <param name="fetch">A delegate that performs the asynchronous fetch operation for a single URI.</param>
    /// <param name="cancellationToken">A cancellation token to observe.</param>
    /// <returns>
    /// A task that represents the asynchronous operation. The task result contains an array of strings
    /// with the fetched content, in the same order as the input <paramref name="uris"/>.
    /// </returns>
    /// <exception cref="ArgumentNullException">
    /// Thrown if <paramref name="uris"/> or <paramref name="fetch"/> is null.
    /// </exception>
    /// <exception cref="OperationCanceledException">
    /// Thrown if the operation is canceled via the <paramref name="cancellationToken"/>.
    /// </exception>
    public static async Task<string[]> DownloadAllAsync(
        IEnumerable<Uri> uris,
        Func<Uri, CancellationToken, Task<string>> fetch,
        CancellationToken cancellationToken)
