        if (uris is null)
        {
            throw new ArgumentNullException(nameof(uris));
        }

        if (fetch is null)
        {
            throw new ArgumentNullException(nameof(fetch));
        }

        // Create a collection of tasks, one for each URI.
        // The LINQ Select statement projects each URI into a call to the fetch delegate.
        // This starts all the fetch operations concurrently because we are not awaiting them
        // individually within a loop.
        var downloadTasks = uris.Select(uri => fetch(uri, cancellationToken));

        // Asynchronously wait for all the download tasks to complete.
        // Task.WhenAll returns a new task that completes when all of the tasks in the
        // enumerable collection have completed.
        // The result of the returned task is an array containing the results of each
        // completed task, in the same order as the input uris.
        // If the cancellationToken is cancelled and the fetch delegate honors it,
        // one or more tasks will be cancelled. Task.WhenAll will then promptly
        // transition to a Canceled state, and the await expression will throw an
        // OperationCanceledException, fulfilling the requirement to stop promptly.
        string[] results = await Task.WhenAll(downloadTasks);

        return results;
    }
}

