        {
            throw new ArgumentNullException(nameof(uris));
        }

        if (fetch is null)
        {
            throw new ArgumentNullException(nameof(fetch));
        }

        // Create a list of tasks by calling the fetch delegate for each URI.
        // This starts all the download operations concurrently.
        // Using ToList() or ToArray() ensures that the enumeration is performed
        // immediately, kicking off all the tasks.
        var downloadTasks = uris.Select(uri => fetch(uri, cancellationToken)).ToList();

        // Asynchronously wait for all the started tasks to complete.
        // Task.WhenAll returns a new task that completes when all of the tasks
        // in the collection have completed.
        // If cancellation is requested and the fetch delegate honors the token,
        // the corresponding task will be canceled, and Task.WhenAll will
        // propagate the OperationCanceledException.
        // The results are returned in an array in the same order as the input tasks.
        string[] results = await Task.WhenAll(downloadTasks);

        return results;
    }
}

