/// <summary>
/// Provides a static method for a producer-consumer pipeline pattern
/// using System.Threading.Channels.
/// </summary>
public static class Pipeline
{
    /// <summary>
    /// Concurrently produces integers from 0 to count-1 into a bounded channel
    /// while a consumer sums them up, returning the total sum.
    /// </summary>
    /// <param name="count">The number of integers to produce (exclusive upper bound).</param>
    /// <returns>A task that represents the asynchronous operation, containing the sum of the integers as a long.</returns>
    public static async Task<long> ProduceConsumeSumAsync(int count)
    {
        if (count <= 0)
        {
            return 0;
        }

        // A bounded channel with a small capacity demonstrates back-pressure,
        // causing the producer to wait if it gets too far ahead of the consumer.
        var channel = Channel.CreateBounded<int>(100);

        // The producer runs in a background task.
        Task producerTask = Task.Run(async () =>
        {
            try
            {
                for (int i = 0; i < count; i++)
                {
                    // Asynchronously writes an item to the channel.
                    // If the channel is full, this call will wait until space is available.
                    await channel.Writer.WriteAsync(i);
                }
            }
            finally
            {
                // Crucially, we mark the channel as complete to signal to the
                // consumer that no more data will be written.
                channel.Writer.Complete();
            }
        });

        // The consumer logic runs in the current async context.
        long sum = 0;

        // Asynchronously reads all items from the channel until it is marked
        // as complete and becomes empty.
        await foreach (int value in channel.Reader.ReadAllAsync())
        {
            sum += value;
        }

        // Await the producer task to ensure it has finished and to propagate
        // any exceptions that may have occurred during production.
        await producerTask;

        return sum;
    }
}

