/// <summary>
/// Provides a static method to demonstrate a producer-consumer pipeline using System.Threading.Channels.
/// </summary>
public static class Pipeline
{
    /// <summary>
    /// Produces integers from 0 to count-1 into a bounded channel and concurrently consumes them to calculate their sum.
    /// </summary>
    /// <param name="count">The number of non-negative integers to produce.</param>
    /// <returns>A task that represents the asynchronous operation, containing the sum of the integers as a <see cref="long"/>.</returns>
    public static Task<long> ProduceConsumeSumAsync(int count)
    {
        if (count <= 0)
        {
            return Task.FromResult(0L);
        }

        // Create a bounded channel with a small capacity to demonstrate back-pressure.
        // The producer will wait if the channel is full.
        var options = new BoundedChannelOptions(100)
        {
            FullMode = BoundedChannelFullMode.Wait,
            SingleReader = true,
            SingleWriter = true
        };
        var channel = Channel.CreateBounded<int>(options);

        // Start the producer task.
        Task producer = Task.Run(async () =>
        {
            try
            {
                for (int i = 0; i < count; i++)
                {
                    // Asynchronously write to the channel. This will wait if the channel is full.
                    await channel.Writer.WriteAsync(i);
                }
            }
            finally
            {
                // Signal that production is complete. This is crucial for the consumer to terminate.
                channel.Writer.Complete();
            }
        });

        // Start the consumer task.
        Task<long> consumer = Task.Run(async () =>
        {
            long sum = 0;

            // Asynchronously read from the channel until it's completed and empty.
            await foreach (int item in channel.Reader.ReadAllAsync())
            {
                sum += item;
            }

            return sum;
        });

        // Return the consumer task, which will complete with the final sum.
        // The producer task runs concurrently and its completion allows the consumer to finish.
        return consumer;
    }
}

