/// <summary>
/// A static class providing a producer-consumer pipeline implementation.
/// </summary>
public static class Pipeline
{
    /// <summary>
    /// Produces integers from 0 to count-1 into a bounded channel
    /// and concurrently consumes them, returning their sum.
    /// </summary>
    /// <param name="count">The number of integers to produce. Must be non-negative.</param>
    /// <returns>A task that represents the asynchronous operation,
    /// containing the sum of the integers as a long.</returns>
    public static async Task<long> ProduceConsumeSumAsync(int count)
    {
        // Per requirements, return 0 for a count of 0.
        // This also gracefully handles negative counts.
        if (count <= 0)
        {
            return 0L;
        }

        // A small capacity demonstrates back-pressure, causing the producer to wait
        // if it gets too far ahead of the consumer. BoundedChannelFullMode.Wait is
        // the default behavior for WriteAsync, causing it to block until space is available.
        var options = new BoundedChannelOptions(10);
        var channel = Channel.CreateBounded<int>(options);

        // A local static function to produce items into the channel.
        static async Task ProduceAsync(ChannelWriter<int> writer, int itemsToProduce)
        {
            try
            {
                for (int i = 0; i < itemsToProduce; i++)
                {
                    // Asynchronously writes an item, waiting if the channel is full.
                    await writer.WriteAsync(i);
                }
            }
            finally
            {
                // Crucially, mark the channel as complete to signal the consumer
                // that no more items will be written. This is done in a finally
                // block to ensure it happens even if an exception occurs.
                writer.Complete();
            }
        }

        // A local static function to consume items from the channel and sum them.
        static async Task<long> ConsumeAsync(ChannelReader<int> reader)
        {
            long sum = 0;
            // Asynchronously reads all items using IAsyncEnumerable. The loop terminates
            // automatically when the channel is marked as complete and becomes empty.
            await foreach (int item in reader.ReadAllAsync())
            {
                sum += item;
            }
            return sum;
        }

        // Start the producer and consumer tasks to run concurrently.
        Task producerTask = ProduceAsync(channel.Writer, count);
        Task<long> consumerTask = ConsumeAsync(channel.Reader);

        // Wait for both to complete. This is important to ensure that if the producer
        // encounters an error, its exception is observed and propagated by the call.
        await Task.WhenAll(producerTask, consumerTask);

        // The result of the overall operation is the sum calculated by the consumer.
        // We can safely await the result as Task.WhenAll has already completed.
        return await consumerTask;
    }
}

