/// <summary>
/// Provides static methods for calculating statistics.
/// </summary>
public static class Stats
{
    /// <summary>
    /// Calculates the arithmetic mean and maximum value of a sequence of double-precision floating-point numbers.
    /// </summary>
    /// <param name="values">A sequence of double values to process.</param>
    /// <returns>A tuple containing the Mean and Max of the sequence.</returns>
    /// <exception cref="ArgumentNullException">Thrown when <paramref name="values"/> is null.</exception>
    /// <exception cref="ArgumentException">Thrown when <paramref name="values"/> is empty.</exception>
    /// <remarks>
    /// This method enumerates the source sequence exactly once and has O(1) memory complexity.
    /// It is suitable for processing large or non-replayable sequences.
    /// </remarks>
    public static (double Mean, double Max) MeanAndMax(IEnumerable<double> values)
    {
        if (values == null)
        {
            throw new ArgumentNullException(nameof(values));
        }

        using (var enumerator = values.GetEnumerator())
        {
            if (!enumerator.MoveNext())
            {
                throw new ArgumentException("The sequence cannot be empty.", nameof(values));
            }

            double firstValue = enumerator.Current;
            double sum = firstValue;
            double max = firstValue;
            long count = 1;

            while (enumerator.MoveNext())
            {
                double currentValue = enumerator.Current;
                sum += currentValue;
                count++;
                if (currentValue > max)
                {
                    max = currentValue;
                }
            }

            return (sum / count, max);
        }
    }
}

