    /// <exception cref="ArgumentNullException">Thrown when the input sequence is null.</exception>
    /// <exception cref="ArgumentException">Thrown when the input sequence is empty.</exception>
    /// <remarks>
    /// This method enumerates the source sequence exactly once and uses O(1) memory,
    /// making it suitable for large or non-replayable data streams.
    /// </remarks>
    public static (double Mean, double Max) MeanAndMax(IEnumerable<double> values)
    {
        if (values is null)
        {
            throw new ArgumentNullException(nameof(values));
        }

        using (var enumerator = values.GetEnumerator())
        {
            // Attempt to get the first element. If the sequence is empty, this fails.
            if (!enumerator.MoveNext())
            {
                throw new ArgumentException("The sequence cannot be empty.", nameof(values));
            }

            // Initialize state with the first element's value.
            double firstValue = enumerator.Current;
            double sum = firstValue;
            double max = firstValue;
            long count = 1;

            // Iterate through the rest of the sequence.
            while (enumerator.MoveNext())
            {
                double currentValue = enumerator.Current;
                sum += currentValue;
                max = Math.Max(max, currentValue);
                count++;
            }

            double mean = sum / count;
            return (mean, max);
        }
    }
}

