        // `out string` parameter. We must declare a local variable of type
        // `string` to pass to it.
        if (_data.TryGetValue(key, out string foundValue))
        {
            // If the key is found, TryGetValue returns true and the compiler,
            // respecting the [MaybeNullWhen(false)] attribute on TryGetValue,
            // knows that `foundValue` is not null in this block.
            value = foundValue;
            return true;
        }

        // If the key is not found, TryGetValue returns false.
        // We explicitly set the out parameter to null to satisfy the contract.
        value = null;
        return false;
    }
