/// <summary>
/// Provides a static method for scanning text without allocating memory.
/// </summary>
public static class TextScan
{
    /// <summary>
    /// Counts the number of whitespace-separated words in a read-only span of characters.
    /// </summary>
    /// <param name="text">The span of characters to scan.</param>
    /// <returns>The number of words found.</returns>
    /// <remarks>
    /// This method does not allocate any memory on the managed heap.
    /// It considers a word to be any sequence of non-whitespace characters.
    /// Multiple consecutive whitespace characters are treated as a single separator.
    /// Leading and trailing whitespace are ignored.
    /// An empty or whitespace-only input will result in a count of 0.
    /// </remarks>
    public static int CountWords(ReadOnlySpan<char> text)
    {
        if (text.IsEmpty)
        {
            return 0;
        }

        int wordCount = 0;
        bool inWord = false;

        foreach (char c in text)
        {
            if (char.IsWhiteSpace(c))
            {
                // We are in whitespace. If we were previously in a word,
                // this marks the end of it.
                inWord = false;
            }
            else
            {
                // We are in a non-whitespace character.
                // If we were not previously in a word, this is the start of a new one.
                if (!inWord)
                {
                    wordCount++;
                    inWord = true;
                }
            }
        }

        return wordCount;
    }
}

