/// <summary>
/// A static class for parsing data from spans without allocations.
/// </summary>
public static class SpanParser
{
    /// <summary>
    /// Parses a comma-separated list of base-10 integers from a span and returns their sum.
    /// </summary>
    /// <param name="csv">A span containing comma-separated integers.</param>
    /// <returns>The sum of the parsed integers. Returns 0 for an empty span.</returns>
    /// <remarks>
    /// This method is allocation-free. It processes the span directly without creating
    /// substrings or other intermediate objects.
    /// Values can be negative. Whitespace around numbers is tolerated.
    /// Empty segments (e.g., from "1,,2") are ignored.
    /// </remarks>
    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        int totalSum = 0;

        // Process the span segment by segment until it's empty.
        while (!csv.IsEmpty)
        {
            // Find the index of the next comma.
            int commaIndex = csv.IndexOf(',');

            // Determine the current segment to parse. If no comma is found,
            // the rest of the span is the last segment. Otherwise, it's the part
            // before the comma.
            ReadOnlySpan<char> segment = (commaIndex == -1) 
                ? csv 
                : csv[..commaIndex];

            // Parse the segment if it's not empty or just whitespace.
            // int.Parse will handle whitespace around the number (e.g., " 123 "),
            // but will throw a FormatException for a span that is entirely whitespace.
            if (!segment.IsWhiteSpace())
            {
                // int.Parse on a ReadOnlySpan<char> is an efficient, non-allocating way to convert.
                totalSum += int.Parse(segment, NumberStyles.Integer, CultureInfo.InvariantCulture);
            }

            // If no comma was found, we've processed the last segment.
            // Clear the span to terminate the loop.
            // Otherwise, slice the span to begin after the comma for the next iteration.
            csv = (commaIndex == -1) 
                ? ReadOnlySpan<char>.Empty 
                : csv[(commaIndex + 1)..];
        }

        return totalSum;
    }
}

