    /// Parses comma-separated base-10 integers from a ReadOnlySpan and returns their sum.
    /// </summary>
    /// <param name="csv">A span containing comma-separated integers.</param>
    /// <returns>The sum of the parsed integers. An empty span results in a sum of 0.</returns>
    /// <remarks>
    /// This method is allocation-free. It does not create strings or substrings.
    /// It gracefully handles leading/trailing whitespace around numbers, as well as
    /// empty entries (e.g., "1,,2") by treating them as zero or ignoring them.
    /// Negative numbers are supported.
    /// </remarks>
    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        int sum = 0;

        // Continuously slice the span until it is empty.
        while (!csv.IsEmpty)
        {
            // Find the next comma.
            int commaIndex = csv.IndexOf(',');

            // Determine the slice for the current number.
            // If no comma is found, the slice is the rest of the span.
            // Otherwise, it's the portion of the span before the comma.
            ReadOnlySpan<char> numberSlice = (commaIndex == -1)
                ? csv
                : csv[..commaIndex];

            // TryParse is used for robustness. It handles whitespace and returns false
            // for empty or malformed slices without throwing an exception.
            // Note: int.TryParse on a span defaults to NumberStyles.Integer,
            // which allows leading/trailing whitespace and a leading sign.
            if (int.TryParse(numberSlice, out int value))
            {
                sum += value;
            }

            // If no comma was found, we have processed the last segment. Exit the loop.
            if (commaIndex == -1)
            {
                break;
            }

            // Slice the span to begin after the comma for the next iteration.
            // This safely handles trailing commas, resulting in an empty span.
            csv = csv[(commaIndex + 1)..];
        }

        return sum;
    }
