/// <summary>
/// Provides a static method to parse integers from a comma-separated span of characters.
/// </summary>
public static class SpanParser
{
    /// <summary>
    /// Parses a comma-separated sequence of base-10 integers from a span and returns their sum.
    /// This method is allocation-free.
    /// </summary>
    /// <param name="csv">A read-only span of characters containing comma-separated integers.</param>
    /// <returns>The sum of the parsed integers. Returns 0 for an empty span.</returns>
    /// <remarks>
    /// The parsing is done directly on the span slices without creating any substrings.
    /// It handles positive and negative integers. Whitespace around numbers is handled by `int.Parse`.
    /// Segments that are empty or contain only whitespace (e.g., from "1,,2" or "1, ,2") are skipped.
    /// Malformed number segments will cause a <see cref="FormatException"/>.
    /// </remarks>
    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        int totalSum = 0;
        var remainingSpan = csv;

        // Loop through the span, processing one number at a time.
        while (!remainingSpan.IsEmpty)
        {
            // Find the next comma.
            int commaIndex = remainingSpan.IndexOf(',');

            ReadOnlySpan<char> numberSpan;

            if (commaIndex == -1)
            {
                // No more commas; the rest of the span is the last number.
                numberSpan = remainingSpan;
                remainingSpan = ReadOnlySpan<char>.Empty; // Ensure the loop terminates.
            }
            else
            {
                // Slice the span to get the part before the comma.
                numberSpan = remainingSpan.Slice(0, commaIndex);
                // Advance the remaining span past the number and the comma.
                remainingSpan = remainingSpan.Slice(commaIndex + 1);
            }

            // Skip empty segments (e.g., from "1,,2"). int.Parse would throw on an empty span.
            if (!numberSpan.IsEmpty)
            {
                // Parse the number directly from the character span.
                // int.Parse on a span implicitly handles leading and trailing whitespace.
                totalSum += int.Parse(numberSpan);
            }
        }

        return totalSum;
    }
}
